using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");
            entity.HasIndex(p => p.Sku);

            // EF Core 9 breaking change #1: discriminator property renamed from
            // "Discriminator" to "$type". Preserve the old name so existing 500K
            // documents and direct SQL queries (WHERE c.Discriminator = ...) keep working.
            entity.HasDiscriminator<string>("Discriminator");

            // EF Core 9 breaking change #2: id values no longer include the
            // discriminator prefix. Old format: "Product|123", new default: "123".
            // Preserve the old format so existing documents remain readable.
            entity.HasPartitionKey(p => p.Id);
            entity.Property(p => p.Id).ToJsonPropertyName("id");
        });

        // Keep the EF8-era "TypeName|Key" id format for all entities.
        modelBuilder.ConfigureConventions(conventions =>
        {
            conventions.ConfigureId((entityType, id) =>
                id.HasIdValueGeneration(Microsoft.EntityFrameworkCore.Cosmos.ValueGeneration.IdValueGeneration.DiscriminatorAndKey));
        });
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

